class Solution {
    public void leftBoundary(TreeNode node, List<Integer> boundary) {
        if (node == null || (node.left == null && node.right == null)) return;
        boundary.add(node.val);
        if (node.left != null) leftBoundary(node.left, boundary);
        else leftBoundary(node.right, boundary);
    }

    public void rightBoundary(TreeNode node, List<Integer> boundary) {
        if (node == null || (node.left == null && node.right == null)) return;
        if (node.right != null) rightBoundary(node.right, boundary);
        else rightBoundary(node.left, boundary);
        boundary.add(node.val);
    }

    public void leaves(TreeNode node, List<Integer> boundary) {
        if (node == null) return;
        if (node.left == null && node.right == null) {
            boundary.add(node.val);
        }
        leaves(node.left, boundary);
        leaves(node.right, boundary);
    }

    public List<Integer> boundaryOfBinaryTree(TreeNode root) {
        List<Integer> res = new ArrayList<>();
        if (root == null) return res;
        res.add(root.val);
        leftBoundary(root.left, res);
        leaves(root, res);
        rightBoundary(root.right, res);
        return res;
    }
}
